import{_ as e,o as i,c as t,aq as l}from"./chunks/framework.DLfWLF6u.js";const m=JSON.parse('{"title":"4 Skills I’m Learning that AI Can’t Replace (backed by data)","description":"","frontmatter":{},"headers":[],"relativePath":"AI/JeffSu/4-skills-im-learning-that-ai-cant-replace.md","filePath":"AI/JeffSu/4-skills-im-learning-that-ai-cant-replace.md","lastUpdated":0}'),n={name:"AI/JeffSu/4-skills-im-learning-that-ai-cant-replace.md"};function r(o,a,s,h,c,d){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="_4-skills-i-m-learning-that-ai-can-t-replace-backed-by-data" tabindex="-1">4 Skills I’m Learning that AI Can’t Replace (backed by data) <a class="header-anchor" href="#_4-skills-i-m-learning-that-ai-can-t-replace-backed-by-data" aria-label="Permalink to “4 Skills I’m Learning that AI Can’t Replace (backed by data)”">​</a></h1><h2 id="video-summary-english" tabindex="-1">Video Summary (English) <a class="header-anchor" href="#video-summary-english" aria-label="Permalink to “Video Summary (English)”">​</a></h2><ul><li>Knowing how to &quot;use AI&quot; is now table stakes for the modern workplace.</li><li>The video covers 4 specific skills that will help you get ahead in the AI era.</li><li>Each skill is backed by research from top institutions: Wharton, Harvard, BCG, and MIT.</li><li><strong>Skill 1 (The Cockpit Rule):</strong> A mental model for deciding when to delegate, collaborate, or go manual with AI.</li><li><strong>Skill 2 (Build the Rails):</strong> How to design workflows that compound and improve as AI improves.</li><li><strong>Skill 3 (The Storytelling Moat):</strong> Why storytelling remains your strongest and most irreplaceable moat.</li><li><strong>Skill 4 (Manual Override):</strong> How to keep your critical thinking sharp instead of letting it atrophy.</li></ul><h2 id="视频总结-chinese" tabindex="-1">视频总结 (Chinese) <a class="header-anchor" href="#视频总结-chinese" aria-label="Permalink to “视频总结 (Chinese)”">​</a></h2><ul><li>知道如何“使用人工智能”现在已成为现代职场的基本要求。</li><li>本视频涵盖了 4 项能帮助你在人工智能时代保持领先的技能。</li><li>每项技能都有顶尖机构的研究支持：沃顿商学院、哈佛大学、波士顿咨询公司和麻省理工学院。</li><li><strong>技能 1 (驾驶舱法则)：</strong> 这是一个心智模型，用于决定何时将任务委派给人工智能，何时与人工智能合作，或何时进行手动操作。</li><li><strong>技能 2 (铺设轨道)：</strong> 如何设计随着人工智能的进步而产生复利并不断优化的工作流。</li><li><strong>技能 3 (讲故事的护城河)：</strong> 为什么讲故事仍然是你最强大且不可替代的护城河。</li><li><strong>技能 4 (手动干预)：</strong> 如何保持你敏锐的批判性思维，而不是让它萎缩。</li></ul><hr><p>以上是我用antigravity的workflow完成的一个视频总结文章.旨在完成一个过程:看视频 -&gt; 英文总结 -&gt; 中文总结 -&gt; 作为文章发布上来.<br> 不过看来,任重道远.这翻译的是什么东西?!?!总结是总结出来了,但你看看这是人话吗?(好像也确实不是人写出来的)</p>',7)])])}const p=e(n,[["render",r]]);export{m as __pageData,p as default};
